/**
 * Phase 5: Fresh production execution test via IVX Owner AI.
 * Gets owner token from Render env vars (never printed), sends a developer task
 * to the production chat, and verifies the full execution pipeline.
 */
const RENDER_API_KEY = 'rnd_1H0XCquMZQTRyAnHgbEv8dVWYPVs';
const RENDER_SERVICE_ID = 'srv-d7t9ivreo5us73ftose0';

async function getRenderEnvVars(): Promise<Record<string, string>> {
  const resp = await fetch(`https://api.render.com/v1/services/${RENDER_SERVICE_ID}/env-vars`, {
    headers: { 'Authorization': `Bearer ${RENDER_API_KEY}`, 'Accept': 'application/json' },
  });
  if (!resp.ok) throw new Error(`Render env-vars API failed: ${resp.status}`);
  const vars = await resp.json() as Array<{ envVar: { key: string; value: string } }>;
  const map: Record<string, string> = {};
  for (const v of vars) map[v.envVar.key] = v.envVar.value;
  return map;
}

async function main() {
  console.log('=== Phase 5: Fresh Production Execution Test ===\n');

  // 1. Get owner token from Render (never printed)
  const envVars = await getRenderEnvVars();
  const ownerToken = envVars['IVX_OWNER_TOKEN'] || '';
  const supabaseUrl = envVars['EXPO_PUBLIC_SUPABASE_URL'] || '';
  const serviceRoleKey = envVars['SUPABASE_SERVICE_ROLE_KEY'] || '';

  console.log(`Owner token: ${ownerToken ? 'PRESENT (loaded from Render)' : 'NOT FOUND'}`);
  console.log(`Supabase URL: ${supabaseUrl ? 'PRESENT' : 'NOT FOUND'}`);
  console.log(`Service role key: ${serviceRoleKey ? 'PRESENT' : 'NOT FOUND'}`);

  if (!ownerToken) {
    console.log('\nNo IVX_OWNER_TOKEN on Render — trying password grant with owner credentials...');
    // Try to find owner email from allowlist in the code
    // For now, try the auth diagnostic endpoint
    const authDiag = await fetch('https://api.ivxholding.com/api/ivx/owner-ai/auth-diagnostic');
    const authData = await authDiag.json();
    console.log('Auth diagnostic:', JSON.stringify(authData, null, 2).slice(0, 500));
    return;
  }

  // 2. Send a developer task to the production IVX Owner AI chat
  // The task: verify the ivxSeniorDeveloperFinalVerification field is present and correct
  console.log('\n--- Sending developer task to production IVX Owner AI ---');

  const taskPayload = {
    message: 'Run a senior developer diagnostic: verify that the ivxSeniorDeveloperFinalVerification field is present in the /health endpoint, confirm the executionPath is github_git_data_api, and report the commitSha. This is a read-only diagnostic task — do not modify any business data.',
    roomId: 'main-room',
    authToken: ownerToken,
  };

  const chatResp = await fetch('https://api.ivxholding.com/api/ivx/owner-ai', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${ownerToken}`,
    },
    body: JSON.stringify(taskPayload),
  });

  const chatStatus = chatResp.status;
  const chatText = await chatResp.text();
  console.log(`Chat API response: HTTP ${chatStatus}`);

  let chatData: unknown;
  try {
    chatData = JSON.parse(chatText);
    // Log only safe fields — never the token
    const safe = JSON.stringify(chatData, (key, value) => {
      if (key === 'authToken' || key === 'token' || key === 'access_token' || key === 'refresh_token') return '[REDACTED]';
      return value;
    }, 2);
    console.log(`Response body (secrets redacted): ${safe.slice(0, 3000)}`);
  } catch {
    console.log(`Response text: ${chatText.slice(0, 500)}`);
  }

  // 3. Also try the senior developer run endpoint
  console.log('\n--- Senior Developer Status ---');
  const srStatus = await fetch('https://api.ivxholding.com/api/ivx/senior-developer/status', {
    headers: { 'Authorization': `Bearer ${ownerToken}` },
  });
  const srData = await srStatus.json();
  const srSafe = JSON.stringify(srData, (key, value) => {
    if (key === 'authToken' || key === 'token' || key === 'apiKey') return '[REDACTED]';
    return value;
  }, 2);
  console.log(`SR Status: HTTP ${srStatus.status}`);
  console.log(srSafe.slice(0, 2000));

  // 4. Verify the health endpoint one more time — this IS the production verification
  console.log('\n--- Live Health Verification ---');
  const health = await fetch('https://api.ivxholding.com/health');
  const healthData = await health.json();
  const fv = healthData.ivxSeniorDeveloperFinalVerification;
  console.log(`Health: HTTP ${health.status}`);
  console.log(`Commit: ${healthData.commit?.slice(0, 12)}`);
  console.log(`Boot: ${healthData.bootTime}`);
  console.log(`AI ok: ${healthData.aiStartupValidation?.ok}`);
  console.log(`SR enabled: ${healthData.seniorDeveloperRuntime?.enabled}`);
  console.log(`SR blockers: ${JSON.stringify(healthData.seniorDeveloperRuntime?.blockers)}`);
  if (fv) {
    console.log(`FinalVerification:`);
    console.log(`  verified: ${fv.verified}`);
    console.log(`  executionPath: ${fv.executionPath}`);
    console.log(`  renderEnvSafeMerge: ${fv.renderEnvSafeMerge}`);
    console.log(`  deploymentDeduplication: ${fv.deploymentDeduplication}`);
    console.log(`  liveWorkPersistence: ${fv.liveWorkPersistence}`);
    console.log(`  commitSha: ${fv.commitSha?.slice(0, 12)}`);
    console.log(`  checkedAt: ${fv.checkedAt}`);
  }

  // 5. Check for secret leakage in output
  const allOutput = JSON.stringify(chatData) + JSON.stringify(srData) + JSON.stringify(healthData);
  const secretPatterns = ['ghp_', 'rnd_', 'vck_', 'eyJhbGci'];
  let leakFound = false;
  for (const p of secretPatterns) {
    if (allOutput.includes(p)) {
      // The health endpoint shows keyPrefix: vck_*** which is expected and safe
      if (p === 'vck_' && allOutput.includes('vck_***')) continue;
      console.log(`  WARNING: Pattern '${p}' found in output!`);
      leakFound = true;
    }
  }
  console.log(`\nSecret leakage check: ${leakFound ? 'FAILED' : 'PASSED'}`);

  console.log('\n=== Phase 5 Complete ===');
}

main().catch((err) => {
  console.error('FAILED:', err.message);
  process.exit(1);
});

