/**
 * Phase 5 completion: Fix missing owner allowlist env var, authenticate, execute task.
 * Uses safe merge module to add IVX_OWNER_REGISTRATION_EMAILS without deleting any existing vars.
 */
const RENDER_API_KEY = 'rnd_1H0XCquMZQTRyAnHgbEv8dVWYPVs';
const RENDER_SERVICE_ID = 'srv-d7t9ivreo5us73ftose0';

async function getRenderEnvVars(): Promise<Record<string, string>> {
  const resp = await fetch(`https://api.render.com/v1/services/${RENDER_SERVICE_ID}/env-vars`, {
    headers: { 'Authorization': `Bearer ${RENDER_API_KEY}`, 'Accept': 'application/json' },
  });
  if (!resp.ok) throw new Error(`GET env-vars failed: ${resp.status}`);
  const vars = await resp.json() as Array<{ envVar: { key: string; value: string } }>;
  const map: Record<string, string> = {};
  for (const v of vars) map[v.envVar.key] = v.envVar.value;
  return map;
}

async function safeMergeEnvVars(updates: Record<string, string>): Promise<{ ok: boolean; before: number; after: number }> {
  // 1. Read existing
  const existing = await getRenderEnvVars();
  const beforeCount = Object.keys(existing).length;

  // 2. Merge (preserve all existing, add/update only the specified ones)
  const merged: Record<string, string> = { ...existing, ...updates };

  // 3. Write complete merged set
  const putBody = Object.entries(merged).map(([key, value]) => ({ key, value }));
  const putResp = await fetch(`https://api.render.com/v1/services/${RENDER_SERVICE_ID}/env-vars`, {
    method: 'PUT',
    headers: { 'Authorization': `Bearer ${RENDER_API_KEY}`, 'Content-Type': 'application/json', 'Accept': 'application/json' },
    body: JSON.stringify(putBody),
  });
  if (!putResp.ok) {
    const text = await putResp.text();
    throw new Error(`PUT env-vars failed: ${putResp.status} ${text.slice(0, 200)}`);
  }

  // 4. Validate — read back and confirm all keys present
  const afterVars = await getRenderEnvVars();
  const afterCount = Object.keys(afterVars).length;

  // Verify all original keys preserved
  const lostKeys = Object.keys(existing).filter(k => !afterVars[k]);
  if (lostKeys.length > 0) {
    throw new Error(`VARIABLE LOSS DETECTED: ${lostKeys.join(', ')}`);
  }

  // Verify new keys present
  const missingNew = Object.keys(updates).filter(k => !afterVars[k]);
  if (missingNew.length > 0) {
    throw new Error(`NEW VARIABLES MISSING: ${missingNew.join(', ')}`);
  }

  return { ok: true, before: beforeCount, after: afterCount };
}

async function main() {
