async function countRows(url: string, key: string, table: string): Promise<number> {
  for (const col of ['id', '*']) {
    try {
      const resp = await fetch(`${url}/rest/v1/${table}?select=${col}&limit=1`, {
        headers: { 'apikey': key, 'Authorization': `Bearer ${key}`, 'Prefer': 'count=exact', 'Range': '0-0' },
      });
      if (resp.ok) {
        const range = resp.headers.get('content-range');
        if (range) {
          const m = range.match(/\/(\d+)/);
          if (m) return parseInt(m[1], 10);
        }
      }
    } catch {}
  }
  return -1;
}

function redact(obj: unknown): string {
  return JSON.stringify(obj, (k, v) => {
    if (k === 'access_token' || k === 'refresh_token' || k === 'token' || k === 'authToken' || k === 'apiKey' || k === 'serviceRoleKey' || k === 'password') return '[REDACTED]';
