    // Redact sensitive fields
    const safe = JSON.stringify(taskData, (k, v) => {
      if (k === 'access_token' || k === 'refresh_token' || k === 'token' || k === 'authToken') return '[REDACTED]';
      return v;
    }, 2);
    console.log(`Response (redacted, first 3000 chars):\n${safe.slice(0, 3000)}`);
  } catch {
    console.log(`Response text: ${taskText.slice(0, 1000)}`);
  }

  // 3. Check SR status with owner token
  console.log('\nSenior developer status...');
  const srResp = await fetch('https://api.ivxholding.com/api/ivx/senior-developer/status', {
    headers: { 'Authorization': `Bearer ${ownerToken}` },
  });
  const srData = await srResp.json();
  const srSafe = JSON.stringify(srData, (k, v) => {
    if (k === 'access_token' || k === 'token' || k === 'apiKey') return '[REDACTED]';
    return v;
  }, 2);
  console.log(`SR HTTP: ${srResp.status}`);
  console.log(srSafe.slice(0, 2000));

  // 4. Check credential audit with owner token
  console.log('\nCredential audit...');
  const caResp = await fetch('https://api.ivxholding.com/api/ivx/senior-developer/credential-audit', {
    headers: { 'Authorization': `Bearer ${ownerToken}` },
  });
  const caData = await caResp.json();
  const caSafe = JSON.stringify(caData, (k, v) => {
    if (typeof v === 'string' && (v.startsWith('ghp_') || v.startsWith('rnd_') || v.startsWith('eyJ') || v.startsWith('vck_'))) return '[REDACTED]';
    if (k === 'access_token' || k === 'token' || k === 'apiKey') return '[REDACTED]';
    return v;
  }, 2);
  console.log(`CA HTTP: ${caResp.status}`);
  console.log(caSafe.slice(0, 2000));
}

main().catch(e => { console.error('FAILED:', e.message); process.exit(1); });
